"use strict";(self.webpackChunkreact_native_headless_calendar_docs=self.webpackChunkreact_native_headless_calendar_docs||[]).push([[211],{7539:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/react-native-headless-calendar/docs/intro","label":"Introduction","docId":"intro","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/installation","label":"Installation","docId":"installation","unlisted":false},{"type":"category","label":"Core Concepts","items":[{"type":"link","href":"/react-native-headless-calendar/docs/core-concepts/mental-model","label":"Mental Model","docId":"core-concepts/mental-model","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/core-concepts/calendar-systems","label":"Calendar Systems","docId":"core-concepts/calendar-systems","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Hooks & Selectors","items":[{"type":"link","href":"/react-native-headless-calendar/docs/hooks/providers","label":"Providers","docId":"hooks/providers","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/hooks/use-calendar-selector","label":"use*CalendarSelector","docId":"hooks/use-calendar-selector","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/hooks/use-calendar-actions","label":"use*CalendarActions","docId":"hooks/use-calendar-actions","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/hooks/selectors","label":"Built-in Selectors","docId":"hooks/selectors","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Calendar Systems","items":[{"type":"link","href":"/react-native-headless-calendar/docs/systems/gregorian","label":"Gregorian Calendar System","docId":"systems/gregorian","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/systems/hijri","label":"Hijri Calendar System","docId":"systems/hijri","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/systems/jalali","label":"Jalali (Persian) Calendar System","docId":"systems/jalali","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/systems/custom-system","label":"Custom Calendar System","docId":"systems/custom-system","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Types & Interfaces","items":[{"type":"link","href":"/react-native-headless-calendar/docs/types/calendar-system","label":"CalendarSystem","docId":"types/calendar-system","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/types/day-cell-info","label":"Day Cell Info","docId":"types/day-cell-info","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/types/calendar-modifiers","label":"CalendarModifiers","docId":"types/calendar-modifiers","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/types/calendar-matcher","label":"CalendarMatcher","docId":"types/calendar-matcher","unlisted":false},{"type":"link","href":"/react-native-headless-calendar/docs/types/calendar-selection-payload","label":"Selection Payloads","docId":"types/calendar-selection-payload","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"core-concepts/calendar-systems":{"id":"core-concepts/calendar-systems","title":"Calendar Systems","description":"A calendar system is an adapter implementing CalendarSystem. The store never inspects dates directly \u2014 every operation goes through the active system. That\'s how Hijri, Jalali, and any custom calendar plug in without the core knowing they exist.","sidebar":"tutorialSidebar"},"core-concepts/mental-model":{"id":"core-concepts/mental-model","title":"Mental Model","description":"react-native-headless-calendar is a state primitive, not a UI kit. Once you internalise the model below, any calendar UI is a thin layer of your own components on top of the same two hooks.","sidebar":"tutorialSidebar"},"hooks/providers":{"id":"hooks/providers","title":"Providers","description":"SingleDateProvider, RangeDateProvider, and MultipleDateProvider \u2014 props, callbacks, and when to use each.","sidebar":"tutorialSidebar"},"hooks/selectors":{"id":"hooks/selectors","title":"Built-in Selectors","description":"Pre-built selector functions for the three most common views. Pass them to the matching use*CalendarSelector hook.","sidebar":"tutorialSidebar"},"hooks/use-calendar-actions":{"id":"hooks/use-calendar-actions","title":"use*CalendarActions","description":"Returns every mutator the calendar exposes \u2014 selection, navigation, confirm, clear, and system switching \u2014 as a single subscription-free, identity-stable object.","sidebar":"tutorialSidebar"},"hooks/use-calendar-selector":{"id":"hooks/use-calendar-selector","title":"use*CalendarSelector","description":"Subscribe to any slice of the store snapshot with granular re-renders. Each selection mode has its own hook \u2014 use the one that matches your provider.","sidebar":"tutorialSidebar"},"installation":{"id":"installation","title":"Installation","description":"Optional \u2014 Hijri Calendar","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"react-native-headless-calendar is a headless, hooks-only calendar primitive for React Native \u2014 one provider per selection mode, two hooks, typed selectors.","sidebar":"tutorialSidebar"},"systems/custom-system":{"id":"systems/custom-system","title":"Custom Calendar System","description":"You can implement any calendar system by creating a CalendarSystem adapter.","sidebar":"tutorialSidebar"},"systems/gregorian":{"id":"systems/gregorian","title":"Gregorian Calendar System","description":"The Gregorian calendar system is the default calendar system. It has zero dependencies and uses pure arithmetic for all calculations.","sidebar":"tutorialSidebar"},"systems/hijri":{"id":"systems/hijri","title":"Hijri Calendar System","description":"The Hijri (Islamic) calendar system. Requires @tabby_ai/hijri-converter or a compatible converter.","sidebar":"tutorialSidebar"},"systems/jalali":{"id":"systems/jalali","title":"Jalali (Persian) Calendar System","description":"The Jalali (Persian/Solar Hijri) calendar system. Requires moment-jalaali.","sidebar":"tutorialSidebar"},"types/calendar-matcher":{"id":"types/calendar-matcher","title":"CalendarMatcher","description":"A CalendarMatcher selects which native dates match a modifier or disabled rule. Three shapes are supported uniformly:","sidebar":"tutorialSidebar"},"types/calendar-modifiers":{"id":"types/calendar-modifiers","title":"CalendarModifiers","description":"Named flags you attach to days for styling (dots, tints, badges). Modifiers are evaluated when the day grid is built and exposed on each cell as cell.modifiers[name].","sidebar":"tutorialSidebar"},"types/calendar-selection-payload":{"id":"types/calendar-selection-payload","title":"Selection Payloads","description":"Each provider fires mode-specific payloads on onChange and onConfirm. The Gregorian fields are always native JS Date values anchored at UTC midnight of the selected day, so JSON.stringify / toISOString round-trip cleanly regardless of the user\'s timezone. The system field carries the same selection expressed in the active calendar system.","sidebar":"tutorialSidebar"},"types/calendar-system":{"id":"types/calendar-system","title":"CalendarSystem","description":"The CalendarSystem interface is the core abstraction that enables multi-calendar support. Implement this interface to add support for any calendar system (Gregorian, Hijri, Chinese, Ethiopian, etc.).","sidebar":"tutorialSidebar"},"types/day-cell-info":{"id":"types/day-cell-info","title":"Day Cell Info","description":"Each visible day in the grid is described by a mode-specific cell type. All extend the same base fields.","sidebar":"tutorialSidebar"}}}}')}}]);